const orgId = $('Supabase - Lookup Org').first().json.org_id;
const runId = `${$execution?.id ?? 'exec'}-${new Date().toISOString()}`;
return $input.all().map(item => ({
  json: {
    fileId: item.json.id ?? null,
    fileName: item.json.name ?? null,
    mimeType: item.json.mimeType ?? null,
    driveFileUrl: item.json.webViewLink ?? null,
    orgId,
    runId
  }
}));

const allFiles = $input.all();
const dbRows = $('Code - Colapsar Procesados').first().json._procesados || [];
const processedIds = new Set(dbRows.map(r => r.file_id).filter(Boolean));
const seen = new Set();
return allFiles.filter(f => {
  const id = f.json.fileId;
  if (!id || processedIds.has(id) || seen.has(id)) return false;
  seen.add(id);
  return true;
});

const meta = $('Code - Filtrar Nuevos').item.json;
const result = {
  fileId: meta.fileId,
  fileName: meta.fileName,
  mimeType: meta.mimeType,
  driveFileUrl: meta.driveFileUrl,
  orgId: meta.orgId,
  runId: meta.runId
};
if ($input.item.binary && $input.item.binary.data) {
  try {
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    result.base64_image = buffer.toString('base64');
  } catch (err) {
    result._error = true;
    result.motivo = 'error_leyendo_imagen';
  }
} else {
  result._error = true;
  result.motivo = 'sin_datos_binarios';
}
return { json: result };

