const allInputs = $input.all();
const allMeta = $('Code - Convertir a Base64').all().filter(m => !m.json._error);
const results = [];
for (let i = 0; i < allInputs.length; i++) {
  const r = allInputs[i].json.body || allInputs[i].json;
  const orig = allMeta[i] ? allMeta[i].json : {};
  const meta = { fileId: orig.fileId, fileName: orig.fileName, mimeType: orig.mimeType, driveFileUrl: orig.driveFileUrl, orgId: orig.orgId, runId: orig.runId };
  if (r.error || !r.choices?.length) {
    results.push({ json: { ...meta, _error: true, motivo: 'openai_api_error', raw_data: JSON.stringify(r).slice(0, 500) } });
    continue;
  }
  const rawText = r.choices[0]?.message?.content || '';
  let parsed;
  try { parsed = JSON.parse(rawText.replace(/```json\\s*|\\s*```/g, '').trim()); } catch (e) {
    results.push({ json: { ...meta, _error: true, motivo: 'parse_error', raw_data: rawText.slice(0, 500) } });
    continue;
  }
  const tipo = parsed.tipo || 'lead';
  const confianza = parsed.confianza || 'baja';
  const personas = Array.isArray(parsed.personas) ? parsed.personas : [];
  const cuenta = parsed.cuenta_hycite || {};
  if (tipo === 'revision' || confianza === 'baja') {
    results.push({ json: { ...meta, _error: true, motivo: 'baja_confianza', tipo_tentativo: tipo, confianza_ia: confianza, raw_data: JSON.stringify(parsed).slice(0, 1000) } });
    continue;
  }
  if (personas.length === 0) {
    results.push({ json: { ...meta, _error: true, motivo: 'sin_personas', raw_data: JSON.stringify(parsed).slice(0, 1000) } });
    continue;
  }
  for (const p of personas) {
    results.push({ json: {
      ...meta, tipo, confianza,
      nombre: p.nombre, apellido: p.apellido,
      telefono_1: p.telefono_1, telefono_2: p.telefono_2, telefono_trabajo: p.telefono_trabajo,
      email: p.email, direccion: p.direccion, apartamento: p.apartamento,
      ciudad: p.ciudad, estado_region: p.estado_region, codigo_postal: p.codigo_postal,
      numero_cuenta: cuenta.numero_cuenta, tipo_cuenta_hycite: cuenta.tipo_cuenta,
      saldo_actual: cuenta.saldo_actual, credito_disponible: cuenta.credito_disponible,
      pago_minimo_mensual: cuenta.pago_minimo_mensual, factor_ingresos: cuenta.factor_ingresos,
      metodo_pago: cuenta.metodo_pago, fecha_orden: cuenta.fecha_orden,
      fecha_cierre: cuenta.fecha_cierre, estado_cuenta: cuenta.estado_cuenta,
      vendedor_hycite_nombre: cuenta.vendedor_hycite_nombre
    }});
  }
}
return results;

const cP = (v) => {
  if (!v) return null;
  const digits = String(v).replace(/\D/g, '');
  if (digits.length < 10) return null;
  return digits.slice(-10);
};
const toNum = (v) => { if (!v) return null; const n = parseFloat(String(v).replace(/[^0-9.]/g, '')); return isNaN(n) ? null : n; };
const toDate = (v) => { if (!v) return null; const m = String(v).match(/(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})/); if (!m) return null; const y = m[3].length===2 ? '20'+m[3] : m[3]; return `${y}-${m[1].padStart(2,'0')}-${m[2].padStart(2,'0')}`; };
const d = $json;
return {
  json: {
    _fileId: d.fileId, _runId: d.runId, _orgId: d.orgId,
    org_id: d.orgId,
    nombre: d.nombre, apellido: d.apellido,
    telefono: cP(d.telefono_1), telefono_casa: cP(d.telefono_2),
    email: d.email || null, direccion: d.direccion || null, apartamento: d.apartamento || null,
    ciudad: d.ciudad || null, estado_region: d.estado_region || null, codigo_postal: d.codigo_postal || null,
    tipo_cuenta_hycite: d.tipo_cuenta_hycite || null,
    saldo_actual: d.saldo_actual,
    credito_disponible: toNum(d.credito_disponible),
    pago_minimo_mensual: toNum(d.pago_minimo_mensual),
    factor_ingresos: toNum(d.factor_ingresos),
    metodo_pago: d.metodo_pago || null,
    fecha_orden: toDate(d.fecha_orden), fecha_cierre: toDate(d.fecha_cierre),
    estado_cuenta: d.estado_cuenta || null,
    vendedor_hycite_nombre: d.vendedor_hycite_nombre || null,
    fuente_import: 'import_imagen_gdrive',
    import_file_name: d.fileName, import_drive_url: d.driveFileUrl
  }
};

